SELECT COUNT(AUTH_CD)
  FROM STOCAUPF
 WHERE GATE_CD = #{ses.gateCd}
   AND AUTH_CD = #{AUTH_CD}

mapper.insert:
INSERT INTO STOCAUPF (
       GATE_CD
     , AUTH_CD
     , REG_DATE
     , REG_USER_ID
     , MOD_DATE
     , MOD_USER_ID
     , DEL_FLAG
     , MAIN_MODULE_TYPE
     , USER_TYPE
) VALUES (
       #{ses.gateCd}
     , #{AUTH_CD}
     , SYSDATE
     , #{ses.userId}
     , SYSDATE
     , #{ses.userId}
     , '0'
     , #{MAIN_MODULE_TYPE}
     , #{USER_TYPE}
)

mapper.update:
UPDATE STOCAUPF SET
      MAIN_MODULE_TYPE = #{MAIN_MODULE_TYPE}
    , USER_TYPE = #{USER_TYPE}
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , DEL_FLAG = '0'
 WHERE GATE_CD = #{ses.gateCd}
   AND AUTH_CD = #{AUTH_CD}

UPDATE STOCAUPF SET
      DEL_FLAG = '1'
    , MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
 WHERE GATE_CD = #{GATE_CD}
   AND AUTH_CD = #{AUTH_CD}
